#include <bits/stdc++.h>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;

    vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        cin >> a[i];
    }

    // Pair each value with its original index
    vector<pair<int, int>> vec(n);
    for (int i = 0; i < n; ++i) {
        vec[i] = {a[i], i};
    }

    sort(vec.begin(), vec.end());

    vector<long long> b(n);
    long long cur = 0;
    for (int i = 0; i < n; ++i) {
        int val = vec[i].first;
        int idx = vec[i].second;
        if (i == 0) {
            cur = val;
        } else {
            cur = max(cur + 1, (long long)val);
        }
        b[idx] = cur;
    }

    for (int i = 0; i < n; ++i) {
        if (i > 0) cout << ' ';
        cout << b[i];
    }
    cout << '\n';

    return 0;
}
